import React from "react";
//import logo from './logo.svg';
import "./App.css";
import Header from "./components/header/Header";
import Main from "./components/main/Main";
import Works from "./components/main/myWorks/Works";
import Learning from "./components/main/learning/Learning";
import { Routes, Route } from "react-router-dom";
import Contacts from "./components/main/contacts/Contacts";
import Footer from "./components/footer/Footer";

function App(props) {
  return (
    <div className="App">
      <Header />
      <section>
        <Routes>
          <Route path="/" element={<Main />}>
            <Route path="/works" element={<Works />} />
            <Route path="/learning" element={<Learning />}>
              <Route path="figma" element={<h1>j9</h1>}></Route>
              <Route path="html"></Route>
              <Route path="css"></Route>
            </Route>
            <Route path="/chat" element={<Contacts />} />
          </Route>
        </Routes>
      </section>
      <Footer className="sdf" />
    </div>
  );
}

export default App;
